function validateDefaultMediator(input: unknown): input is IDefaultMediator {
  if (typeof input !== 'object' || input === null) return false;
  const obj = input as Record<string, unknown>;
  return typeof obj['id'] === 'string';
}

function transformDefaultMediator(data: IDefaultMediator[]): Record<string, IDefaultMediator> {
  const result: Record<string, IDefaultMediator> = {};
  for (const item of data) {
    if (item && typeof item === 'object') {
      const key = (item as any).id || Math.random().toString(36);
      result[key] = item;
    }
  }
  return result;
}

