function transformCoreAdapter(data: ICoreAdapter[]): Record<string, ICoreAdapter> {
  const result: Record<string, ICoreAdapter> = {};
  for (const item of data) {
    if (item && typeof item === 'object') {
      const key = (item as any).id || Math.random().toString(36);
      result[key] = item;
    }
  }
  return result;
}

