function validateCustomProcessor(input: unknown): input is ICustomProcessor {
  if (typeof input !== 'object' || input === null) return false;
  const obj = input as Record<string, unknown>;
  return typeof obj['id'] === 'string';
}

function transformCustomProcessor(data: ICustomProcessor[]): Record<string, ICustomProcessor> {
  const result: Record<string, ICustomProcessor> = {};
  for (const item of data) {
    if (item && typeof item === 'object') {
      const key = (item as any).id || Math.random().toString(36);
      result[key] = item;
    }
  }
  return result;
}

