function transformBaseCommand(data: IBaseCommand[]): Record<string, IBaseCommand> {
  const result: Record<string, IBaseCommand> = {};
  for (const item of data) {
    if (item && typeof item === 'object') {
      const key = (item as any).id || Math.random().toString(36);
      result[key] = item;
    }
  }
  return result;
}

