function validateBaseMediator(input: unknown): input is IBaseMediator {
  if (typeof input !== 'object' || input === null) return false;
  const obj = input as Record<string, unknown>;
  return typeof obj['id'] === 'string';
}

function transformBaseMediator(data: IBaseMediator[]): Record<string, IBaseMediator> {
  const result: Record<string, IBaseMediator> = {};
  for (const item of data) {
    if (item && typeof item === 'object') {
      const key = (item as any).id || Math.random().toString(36);
      result[key] = item;
    }
  }
  return result;
}

