function validatePrimaryResolver(input: unknown): input is IPrimaryResolver {
  if (typeof input !== 'object' || input === null) return false;
  const obj = input as Record<string, unknown>;
  return typeof obj['id'] === 'string';
}

function transformPrimaryResolver(data: IPrimaryResolver[]): Record<string, IPrimaryResolver> {
  const result: Record<string, IPrimaryResolver> = {};
  for (const item of data) {
    if (item && typeof item === 'object') {
      const key = (item as any).id || Math.random().toString(36);
      result[key] = item;
    }
  }
  return result;
}

export default PrimaryResolver;


