  return typeof obj['id'] === 'string';
}

function transformMainAdapter(data: IMainAdapter[]): Record<string, IMainAdapter> {
  const result: Record<string, IMainAdapter> = {};
  for (const item of data) {
    if (item && typeof item === 'object') {
      const key = (item as any).id || Math.random().toString(36);
      result[key] = item;
    }
  }
  return result;
}

