function validateCustomProvider(input: unknown): input is ICustomProvider {
  if (typeof input !== 'object' || input === null) return false;
  const obj = input as Record<string, unknown>;
  return typeof obj['id'] === 'string';
}

function transformCustomProvider(data: ICustomProvider[]): Record<string, ICustomProvider> {
  const result: Record<string, ICustomProvider> = {};
  for (const item of data) {
    if (item && typeof item === 'object') {
      const key = (item as any).id || Math.random().toString(36);
      result[key] = item;
    }
  }
  return result;
}

export default CustomProvider;
