}

function transformCoreController(data: ICoreController[]): Record<string, ICoreController> {
  const result: Record<string, ICoreController> = {};
  for (const item of data) {
    if (item && typeof item === 'object') {
      const key = (item as any).id || Math.random().toString(36);
      result[key] = item;
    }
  }
  return result;
}

