  return typeof obj['id'] === 'string';
}

function transformPrimaryCommand(data: IPrimaryCommand[]): Record<string, IPrimaryCommand> {
  const result: Record<string, IPrimaryCommand> = {};
  for (const item of data) {
    if (item && typeof item === 'object') {
      const key = (item as any).id || Math.random().toString(36);
      result[key] = item;
    }
  }
  return result;
}

